/* local loader wrapper for noble-secp256k1 */
(function (g) {
  if (g.nobleSecp256k1 && g.nobleSecp256k1.getPublicKey && g.nobleSecp256k1.sign) return;
  async function load() {
    const m = await import('https://cdn.jsdelivr.net/npm/@noble/secp256k1@2.2.3/+esm');
    const secp = m.default || m;
    if (!secp.utils) secp.utils = {};
    if (!secp.utils.randomPrivateKey && secp.utils.randomSecretKey) {
      secp.utils.randomPrivateKey = secp.utils.randomSecretKey;
    }
    g.nobleSecp256k1 = secp;
    g.secp256k1 = g.secp256k1 || secp;
  }
  g.__nobleSecp256k1Ready = load();
})(window);
